mapper.select:
/* selectTransferPayment 이송지급 */ SELECT BI.RCVDATE AS TRSDATE, BH.BFHDKEY , GROUP_CONCAT(DISTINCT BC.BTRCNAM) AS BTRCNAM , GROUP_CONCAT(DISTINCT BI.BTRFPA1) AS BTRPAY1 , GROUP_CONCAT(DISTINCT BI.BTRFPA2) AS BTRPAY2 , GROUP_CONCAT(DISTINCT BI.BTRFPA3) AS BTRPAY3 , GROUP_CONCAT(DISTINCT BI.BTRFPA4) AS BTRPAY4 , SUM( CASE WHEN BI.CALWEIG = 'GROSSWG' THEN BI.GROSSWG ELSE BI.SKUWEIG END ) AS TOTALWG , MG.RENAMLC AS RENAMLC , (COUNT(DISTINCT MG.RENAMLC) - 1) as REGICNT , BH.TRFDFPA AS TRSDFPA , SUM(BI.BTRFEP1) AS EXTRAPA , SUM(BI.HOLIPAY) AS HOLIPAY , SUM(BI.BTRFPC1 + BI.BTRFPC2 + BI.BTRFPC3 + BI.BTRFPC4 ) AS PAYMENT , SUM(BI.BTRFPC1 + BI.BTRFPC2 + BI.BTRFPC3 + BI.BTRFPC4 + BI.BTRFEP1 + BI.HOLIPAY ) + BH.TRFDFPA AS TOTPACO , BH.BFHMEMO AS TRSMEMO , MW.WHNAMLC, MVH.VHCFNAM, MVO.VONAMLC, BH.PAYADYN FROM ${userInfo.schema}.BTRFHD BH INNER JOIN ${userInfo.schema}.BTRFIT BI ON BH.WAREKEY = BI.WAREKEY AND BH.BFHDKEY = BI.BFHDKEY INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = BI.BTRCATE INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = BH.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVHCMA MVH ON MVH.VEHICKY = BH.VEHICKY AND MVH.VOWNKEY = BH.VOWNKEY AND MVH.VHUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVOWMA MVO ON MVO.VOWNKEY = BH.VOWNKEY AND MVO.VOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.WRCVIT WI ON WI.WAREKEY = BH.WAREKEY AND WI.RCVDCKY = BI.RCVDCKY AND WI.RCVDCIT = BI.RCVDCIT INNER JOIN ${userInfo.schema}.MREGMA MG ON MG.REGIKEY = WI.REGIMOD AND MG.REUSEYN = 'Y' WHERE BH.WAREKEY = #{param.warekey} AND BH.VEHICKY = #{param.vehicky} AND BH.FCCFMYN = 'Y'
AND BH.FCCDATE >= #{param.confirmdatefrom}
AND BH.FCCDATE <= #{param.confirmdateto}
AND BH.FCCDATE BETWEEN #{param.confirmdatefrom} AND #{param.confirmdateto}
GROUP BY BI.RCVDATE, BH.BFHDKEY, BH.TRFDFPA, BH.TOORGPA , BH.TOSURPA, BH.TOTPACO, BH.BFHMEMO, MW.WHNAMLC , MVH.VHCFNAM, MVO.VONAMLC, BH.PAYADYN

/* selectTransportPayment 운송지급*/ SELECT IFNULL(WH.SPEHDAT, TI.BILDATE) AS TRSDATE , BH.BPHDKEY , GROUP_CONCAT(DISTINCT BC.BTRCNAM) AS BTRCNAM , GROUP_CONCAT(DISTINCT BI.BTRPPAY) AS BTRPAY1 , SUM( CASE WHEN BI.CALWEIG = 'GROSSWG' THEN BI.GROSSWG ELSE BI.SKUWEIG END ) AS TOTALWG , (COUNT(DISTINCT MG.RENAMLC) - 1) as REGICNT , MG.RENAMLC AS RENAMLC , BH.TRPDFPA AS TRSDFPA , SUM(BI.BTRPEPC) AS EXTRAPA , SUM(BI.HOLIPAY) AS HOLIPAY , SUM(BI.BTRPPAY) AS PAYMENT , SUM(BI.BTRPPAY + BI.BTRPEPC + BI.HOLIPAY) + BH.TRPDFPA AS TOTPACO , BH.BPHMEMO AS TRSMEMO , MW.WHNAMLC, MVH.VHCFNAM, MVO.VONAMLC, MW.WAREKEY , BH.PAYADYN FROM ${userInfo.schema}.BTRPHD BH INNER JOIN ${userInfo.schema}.BTRPIT BI ON BH.WAREKEY = BI.WAREKEY AND BH.BPHDKEY = BI.BPHDKEY INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = BI.BTRCATE INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = BH.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVHCMA MVH ON MVH.VEHICKY = BH.VEHICKY AND MVH.VOWNKEY = BH.VOWNKEY AND MVH.VHUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVOWMA MVO ON MVO.VOWNKEY = BH.VOWNKEY AND MVO.VOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.TPLNIT TI ON TI.WAREKEY = BH.WAREKEY AND TI.VHPLNKY = BI.VHPLNKY AND TI.VHPLNIT = BI.VHPLNIT LEFT JOIN ${userInfo.schema}.WSHPIT WS ON WS.WAREKEY = TI.WAREKEY AND WS.SKUMKEY = TI.SKUMKEY LEFT JOIN ${userInfo.schema}.WSHPHD WH ON WH.WAREKEY = WS.WAREKEY AND WH.SHPDCKY = WS.SHPDCKY INNER JOIN ${userInfo.schema}.MREGMA MG ON MG.REGIKEY = BI.REGIMOD AND MG.REUSEYN = 'Y' WHERE BH.WAREKEY = #{param.warekey} AND BH.VEHICKY = #{param.vehicky} AND BH.PCCFMYN = 'Y'
AND BH.PCCDATE >= #{param.confirmdatefrom}
AND BH.PCCDATE <= #{param.confirmdateto}
AND BH.PCCDATE BETWEEN #{param.confirmdatefrom} AND #{param.confirmdateto}
GROUP BY BI.TRNINDT, BH.BPHDKEY, BH.TRPDFPA, BH.TOORGPA , TOTPACO, BH.BPHMEMO, MW.WHNAMLC , MVH.VHCFNAM, MVO.VONAMLC, MW.WAREKEY, BH.PAYADYN

mapper.sql:
SELECT BI.RCVDATE AS TRSDATE , BI.BFHDKEY , GROUP_CONCAT(DISTINCT BC.BTRCNAM) AS BTRCNAM , GROUP_CONCAT(DISTINCT BI.BTRFCH1) AS BTRCHR1 , GROUP_CONCAT(DISTINCT BI.BTRFCH2) AS BTRCHR2 , GROUP_CONCAT(DISTINCT BI.BTRFCH3) AS BTRCHR3 , GROUP_CONCAT(DISTINCT BI.BTRFCH4) AS BTRCHR4 , MG.RENAMLC AS RENAMLC , (COUNT(DISTINCT MG.RENAMLC) - 1) as REGICNT , SUM( CASE WHEN BI.CALWEIG = 'GROSSWG' THEN BI.GROSSWG ELSE BI.SKUWEIG END ) AS TOTALWG , BH.TRFDFCH AS TRSDFPA , SUM(BI.BTRFEC1) AS EXTRACH , SUM(BI.HOLICHR) AS HOLICHR , ( CASE WHEN BI.SBILLTO IS NOT NULL AND TRIM(BI.SBILLTO) != '' THEN SUM(BI.BTRFCC1 + BI.BTRFCC2 + BI.BTRFCC3 + BI.BTRFCC4) ELSE SUM( BI.BTRFCC1 + BI.BTRFCC2 + BI.BTRFCC3 + BI.BTRFCC4 + BI.ADDCHCO) END ) AS CHARGE , ( CASE WHEN BI.SBILLTO IS NOT NULL AND TRIM(BI.SBILLTO) != '' THEN SUM(BI.BTRFCC1 + BI.BTRFCC2 + BI.BTRFCC3 + BI.BTRFCC4 + BI.BTRFEC1+ BI.HOLICHR) + BH.TRFDFCH ELSE SUM(BI.BTRFCC1 + BI.BTRFCC2 + BI.BTRFCC3 + BI.BTRFCC4 + BI.BTRFEC1+ BI.HOLICHR + BI.ADDCHCO) + BH.TRFDFCH END ) AS TOTCHCO , BH.BFHMEMO, MW.WHNAMLC, MW.WAMANNM, MW.WARADDR , BH.FCCDATE AS TCCDATE , MC.CUNAMLC AS BTRFCBT FROM ${userInfo.schema}.BTRFIT BI INNER JOIN ${userInfo.schema}.BTRFHD BH ON BH.BFHDKEY = BI.BFHDKEY AND BH.WAREKEY = BI.WAREKEY INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = BI.BTRCATE INNER JOIN ${userInfo.schema}.MWARMA MW ON BH.WAREKEY = MW.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCUSMA MC ON MC.CUSTKEY = #{param.btrfcbt} AND MC.CUDELYN = 'Y' INNER JOIN ${userInfo.schema}.WRCVIT WI ON WI.WAREKEY = BH.WAREKEY AND WI.RCVDCKY = BI.RCVDCKY AND WI.RCVDCIT = BI.RCVDCIT INNER JOIN ${userInfo.schema}.MREGMA MG ON MG.REGIKEY = WI.REGIORG AND MG.REUSEYN = 'Y' WHERE BI.WAREKEY = #{param.warekey} AND BI.BTRFCBT = #{param.btrfcbt} AND BH.FCCFMYN = 'Y' AND BH.FCCFMYN = 'Y'
AND BH.FCCDATE >= #{param.confirmdatefrom}
AND BH.FCCDATE <= #{param.confirmdateto}
AND BH.FCCDATE BETWEEN #{param.confirmdatefrom} AND #{param.confirmdateto}
GROUP BY BI.RCVDATE, BI.BFHDKEY, BH.TRFDFCH, BH.BFHMEMO , MW.WHNAMLC, MW.WAMANNM, MW.WARADDR, BH.FCCDATE , MC.CUNAMLC

mapper.select:
/* selectTransferSurCharge */ SELECT BI.RCVDATE AS TRSDATE, BH.BFHDKEY , GROUP_CONCAT(DISTINCT BC.BTRCNAM) AS BTRCNAM , GROUP_CONCAT(DISTINCT BI.BTRFCH1) AS BTRCHR1 , GROUP_CONCAT(DISTINCT BI.BTRFCH2) AS BTRCHR2 , GROUP_CONCAT(DISTINCT BI.BTRFCH3) AS BTRCHR3 , GROUP_CONCAT(DISTINCT BI.BTRFCH4) AS BTRCHR4 , MG.RENAMLC AS RENAMLC , (COUNT(DISTINCT MG.RENAMLC) - 1) as REGICNT , SUM( CASE WHEN BI.CALWEIG = 'GROSSWG' THEN BI.GROSSWG ELSE BI.SKUWEIG END ) AS TOTALWG , (SUM(BI.ADDCHCO) + SUM(BI.SURCHCO)) AS CHARGE , (SUM(BI.ADDCHCO) + SUM(BI.SURCHCO)) AS TOTCHCO , BH.BFHMEMO, MW.WHNAMLC, MW.WAMANNM, MW.WARADDR , BH.FCCDATE AS TCCDATE, MC.CUNAMLC AS BTRFCBT FROM ${userInfo.schema}.BTRFHD BH INNER JOIN ${userInfo.schema}.BTRFIT BI ON BH.WAREKEY = BI.WAREKEY AND BH.BFHDKEY = BI.BFHDKEY INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = BI.BTRCATE INNER JOIN ${userInfo.schema}.MWARMA MW ON BH.WAREKEY = MW.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCUSMA MC ON MC.CUSTKEY = BI.SBILLTO AND MC.CUDELYN = 'Y'
INNER JOIN ${userInfo.schema}.WRCVIT WI ON WI.WAREKEY = BH.WAREKEY AND WI.RCVDCKY = BI.RCVDCKY AND WI.RCVDCIT = BI.RCVDCIT INNER JOIN ${userInfo.schema}.MREGMA MG ON MG.REGIKEY = WI.REGIMOD AND MG.REUSEYN = 'Y' WHERE BH.WAREKEY = #{param.warekey} AND BI.SBILLTO = #{param.sbillto} AND BH.FCCFMYN = 'Y'
AND BH.FCCDATE >= #{param.confirmdatefrom}
AND BH.FCCDATE <= #{param.confirmdateto}
AND BH.FCCDATE BETWEEN #{param.confirmdatefrom} AND #{param.confirmdateto}
GROUP BY BI.RCVDATE, BH.BFHDKEY, BH.BFHMEMO, MW.WHNAMLC , MW.WAMANNM, MW.WARADDR, MW.WARADDR, BH.FCCDATE , MC.CUNAMLC

/* selectTransportCharge */ SELECT IFNULL(WH.SPEHDAT, TI.BILDATE) AS TRSDATE, BH.BPHDKEY , GROUP_CONCAT(DISTINCT BC.BTRCNAM) AS BTRCNAM , GROUP_CONCAT(DISTINCT BI.BTRPCHR) AS BTRCHR1 , (COUNT(DISTINCT MG.RENAMLC) - 1) as REGICNT, MG.RENAMLC AS RENAMLC, SUM(CASE WHEN BI.CALWEIG = 'GROSSWG' THEN BI.GROSSWG ELSE BI.SKUWEIG END) AS TOTALWG , BH.TRPDFCH AS TRSDFPA , SUM(BI.BTRPECC) AS EXTRACH , SUM(BI.HOLICHR) AS HOLICHR , SUM( CASE WHEN BI.SBILLTO IS NOT NULL AND TRIM(BI.SBILLTO) != '' THEN BI.BTRPCCO ELSE BI.BTRPCCO + BI.ADDCHCO + BI.SURCHCO END ) AS CHARGE , ( CASE WHEN BI.SBILLTO IS NOT NULL AND TRIM(BI.SBILLTO) != '' THEN SUM(BI.BTRPCCO + BI.BTRPECC + BI.HOLICHR) + BH.TRPDFCH ELSE SUM(BI.BTRPCCO + BI.BTRPECC + BI.HOLICHR + BI.ADDCHCO + BI.SURCHCO) + BH.TRPDFCH END ) AS TOTCHCO , BH.BPHMEMO, MW.WHNAMLC, MW.WAMANNM, MW.WARADDR, BH.PCCDATE AS TCCDATE, MC.CUNAMLC AS BTRFCBT FROM ${userInfo.schema}.BTRPHD BH INNER JOIN ${userInfo.schema}.BTRPIT BI ON BH.WAREKEY = BI.WAREKEY AND BH.BPHDKEY = BI.BPHDKEY INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = BI.BTRCATE INNER JOIN ${userInfo.schema}.TPLNIT TI ON TI.WAREKEY = BH.WAREKEY AND TI.VHPLNKY = BI.VHPLNKY AND TI.VHPLNIT = BI.VHPLNIT LEFT JOIN ${userInfo.schema}.WSHPIT WS ON WS.WAREKEY = TI.WAREKEY AND WS.SKUMKEY = TI.SKUMKEY LEFT JOIN ${userInfo.schema}.WSHPHD WH ON WH.WAREKEY = WS.WAREKEY AND WH.SHPDCKY = WS.SHPDCKY INNER JOIN ${userInfo.schema}.MREGMA MG ON MG.REGIKEY = TI.REGIORG AND MG.REUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MWARMA MW ON BH.WAREKEY = MW.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCUSMA MC ON MC.CUSTKEY = #{param.btrfcbt} AND MC.CUDELYN = 'Y' WHERE BH.WAREKEY = #{param.warekey} AND BI.BTRPCBT = #{param.btrfcbt} AND BH.PCCFMYN = 'Y'
AND BH.PCCDATE >= #{param.confirmdatefrom}
AND BH.PCCDATE <= #{param.confirmdateto}
AND BH.PCCDATE BETWEEN #{param.confirmdatefrom} AND #{param.confirmdateto}
GROUP BY BI.TRNINDT, BH.BPHDKEY, BH.TRPDFCH, BH.TOORGCH , BH.TOSURCH, BH.TOTCHCO, BH.BPHMEMO, MW.WHNAMLC , MW.WAMANNM, MW.WARADDR, BH.PCCDATE, MC.CUNAMLC

/* selectTransportSurCharge */ SELECT IFNULL(WH.SPEHDAT, TI.BILDATE) AS TRSDATE, BH.BPHDKEY , GROUP_CONCAT(DISTINCT BC.BTRCNAM) AS BTRCNAM , GROUP_CONCAT(DISTINCT BI.BTRPCHR) AS BTRCHR1 , (COUNT(DISTINCT MG.RENAMLC) - 1) as REGICNT , MG.RENAMLC AS RENAMLC , SUM( CASE WHEN BI.CALWEIG = 'GROSSWG' THEN BI.GROSSWG ELSE BI.SKUWEIG END ) AS TOTALWG , (SUM(BI.ADDCHCO) + SUM(BI.SURCHCO)) AS CHARGE , (SUM(BI.ADDCHCO) + SUM(BI.SURCHCO)) AS TOTCHCO , BH.BPHMEMO, MW.WHNAMLC, MW.WAMANNM, MW.WARADDR , BH.PCCDATE AS TCCDATE, MC.CUNAMLC AS BTRFCBT FROM ${userInfo.schema}.BTRPHD BH INNER JOIN ${userInfo.schema}.BTRPIT BI ON BH.WAREKEY = BI.WAREKEY AND BH.BPHDKEY = BI.BPHDKEY INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = BI.BTRCATE INNER JOIN ${userInfo.schema}.TPLNIT TI ON TI.WAREKEY = BH.WAREKEY AND TI.VHPLNKY = BI.VHPLNKY AND TI.VHPLNIT = BI.VHPLNIT LEFT JOIN ${userInfo.schema}.WSHPIT WS ON WS.WAREKEY = TI.WAREKEY AND WS.SKUMKEY = TI.SKUMKEY LEFT JOIN ${userInfo.schema}.WSHPHD WH ON WH.WAREKEY = WS.WAREKEY AND WH.SHPDCKY = WS.SHPDCKY INNER JOIN ${userInfo.schema}.MREGMA MG ON MG.REGIKEY = TI.REGIMOD AND MG.REUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MWARMA MW ON BH.WAREKEY = MW.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCUSMA MC ON MC.CUSTKEY = BI.SBILLTO AND MC.CUDELYN = 'Y' WHERE BH.WAREKEY = #{param.warekey} AND BI.SBILLTO = #{param.sbillto}
AND BH.PCCFMYN = 'Y'
AND BH.PCCDATE >= #{param.confirmdatefrom}
AND BH.PCCDATE <= #{param.confirmdateto}
AND BH.PCCDATE BETWEEN #{param.confirmdatefrom} AND #{param.confirmdateto}
GROUP BY BI.TRNINDT, BH.BPHDKEY, BH.BPHMEMO, MW.WHNAMLC , MW.WAMANNM, MW.WARADDR, BH.PCCDATE, MC.CUNAMLC

/* selectPaymentPrintCnt */
SELECT COUNT(PRINTSQ) AS printcount
  FROM ${userData.schema}.SPRTHI
 WHERE WAREKEY = #{param.warekey}
   AND DOCTYPE = #{param.doctype}
   AND PROGRID = #{param.progrid}

   AND BFHDKEY = #{param.bfhdkey}


   AND BPHDKEY = #{param.bphdkey}

/* selectChargePrintCnt */
SELECT COUNT(PRINTSQ) AS printcount
  FROM ${userData.schema}.SPRTHI
 WHERE WAREKEY = #{param.warekey}
   AND DOCTYPE = #{param.doctype}
   AND PROGRID = #{param.progrid}

   AND BFHDKEY = #{param.bfhdkey}


   AND BPHDKEY = #{param.bphdkey}


 	AND CBILLTO = #{param.btrfcbt}


 	AND SBILLTO = #{param.sbillto}

