/* insertPaymentPrintLog */
INSERT INTO ${userData.schema}.SPRTHI(
	PRINTSQ, WAREKEY, DOCCATE, DOCTYPE, PROGRID
	, BFHDKEY, BPHDKEY, PRTDATE, PRTTIME, PRTUSER
	, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME
	, LMOUSER
)VALUES(
	#{saveData.printsq}, #{saveData.warekey}, #{saveData.doccate}
	, #{saveData.doctype}, #{saveData.progrid}

		, #{saveData.bfhdkey}, ''


		, '', #{saveData.bphdkey}

	, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
	, to_char(NOW() ,'YYYYMMDD'), to_char(NOW()  ,'hh24miss'), #{userData.useract}
	, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
)

/* insertChargePrintLog */
