	, #{saveData.doctype}, #{saveData.progrid}

		, #{saveData.btrfcbt}, ''


		, '', #{saveData.sbillto}


		, #{saveData.bfhdkey}, ''


		, '', #{saveData.bphdkey}

	, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
	, to_char(NOW() ,'YYYYMMDD'), to_char(NOW()  ,'hh24miss'), #{userData.useract}
	, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
)
